	/**
	* Track Revision module for WordprocessingML documents.
	*
	* This module provides support for tracking document revisions
	* (insertions, deletions, and formatting changes).
	*
	* Reference: http://officeopenxml.com/WPtrackChanges.php
	*
	* @module
	*/
	/**
	* Attributes for a tracked change element.
	*
	* Represents the common attributes (id, author, date) that appear on track change
	* elements such as insertions (w:ins) and deletions (w:del). These attributes
	* are part of the CT_TrackChange complex type in OOXML.
	*
	* Reference: http://officeopenxml.com/WPtrackChanges.php
	*
	* ## XSD Schema
	* ```xml
	* <xsd:complexType name="CT_TrackChange">
	*   <xsd:complexContent>
	*     <xsd:extension base="CT_Markup">
	*       <xsd:attribute name="author" type="s:ST_String" use="required"/>
	*       <xsd:attribute name="date" type="ST_DateTime" use="optional"/>
	*     </xsd:extension>
	*   </xsd:complexContent>
	* </xsd:complexType>
	*
	* <xsd:complexType name="CT_Markup">
	*   <xsd:attribute name="id" type="ST_DecimalNumber" use="required"/>
	* </xsd:complexType>
	* ```
	*
	* @internal
	*/
	var ChangeAttributes = class extends XmlAttributeComponent {
		constructor(..._args) {
			super(..._args);
			_defineProperty(this, "xmlKeys", {
				id: "w:id",
				author: "w:author",
				date: "w:date"
			});
		}
	};
	//#endregion
	//#region src/file/track-revision/track-revision-components/deletion-track-change.ts
	var DeletionTrackChange = class extends XmlComponent {
		constructor(options) {
			super("w:del");
			this.root.push(new ChangeAttributes({
				id: options.id,
				author: options.author,
				date: options.date
			}));
		}
	};
	//#endregion
	//#region src/file/track-revision/track-revision-components/insertion-track-change.ts
	var InsertionTrackChange = class extends XmlComponent {
		constructor(options) {
			super("w:ins");
			this.root.push(new ChangeAttributes({
				id: options.id,
				author: options.author,
				date: options.date
			}));
		}
	};
