		/** Dark cyan highlight */
		DARK_CYAN: "darkCyan",
		/** Dark gray highlight */
		DARK_GRAY: "darkGray",
		/** Dark green highlight */
		DARK_GREEN: "darkGreen",
		/** Dark magenta highlight */
		DARK_MAGENTA: "darkMagenta",
		/** Dark red highlight */
		DARK_RED: "darkRed",
		/** Dark yellow highlight */
		DARK_YELLOW: "darkYellow",
		/** Green highlight */
